const text = $('Blog Post Agent').first().json.output;
if (!text) {
  throw new Error('No text found from Blog Post Agent');
}
const chunkSize = 4096;
const chunks = [];
for (let i = 0; i < text.length; i += chunkSize) {
  chunks.push({ text: text.slice(i, i + chunkSize) });
}
return chunks;
